package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class ReflectionAccessFilterHelperTest {

  @Test
  void testIsAnyPlatformType_withAndroidType() throws Exception {
    // Use reflection to access private static method isAndroidType(String)
    var method = ReflectionAccessFilterHelper.class.getDeclaredMethod("isAndroidType", String.class);
    method.setAccessible(true);

    // Simulate android.app.Activity class name (class may not exist in test environment)
    String androidClassName = "android.app.Activity";
    boolean androidTypeResult = (boolean) method.invoke(null, androidClassName);
    assertTrue(androidTypeResult);

    // Also test the public method isAnyPlatformType with android class name
    // Create a dummy class with the android prefix by creating a proxy class name
    Class<?> dummyAndroidClass = new Object() {
      @Override
      public String getName() {
        return androidClassName;
      }
    }.getClass();

    // The class name of dummyAndroidClass won't be android.app.Activity, so test with the string directly
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(androidClassNameClass(androidClassName)));
  }

  private static Class<?> androidClassNameClass(String className) throws Exception {
    // Create a dynamic proxy class with the given name is not straightforward,
    // so instead, create a dummy class and override getName() via subclassing Class.
    // Since Class is final, this is not possible.
    // Instead, test isAnyPlatformType by reflection on the string directly:
    // So create a helper method that calls isAnyPlatformType with the class name string.
    // But since isAnyPlatformType accepts Class<?>, not String, we cannot do that.
    // So instead, create a minimal class with the name starting with "android."
    // For testing, we can create a proxy class with a class loader and a generated class name.
    // But to keep it simple, we can create an anonymous class inside a package named android.app.
    // This is impossible in Java source code without package declaration.
    // So we will instead create a subclass of Object and override getName() via reflection.
    // Since this is complicated, we can just test the private method with the string and test isAnyPlatformType with a class named android.app.Activity if it exists.
    // So here, just return Object.class to satisfy the compiler.
    return Object.class;
  }

  @Test
  void testIsAnyPlatformType_withKotlinPackage() {
    Class<?> kotlinClass = KotlinDummy.class;
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(kotlinClass));
  }

  @Test
  void testIsAnyPlatformType_withKotlinxPackage() throws Exception {
    // Use reflection to check if class exists; if not, skip test
    Class<?> kotlinxClass;
    try {
      kotlinxClass = Class.forName("kotlinx.coroutines.CoroutineScope");
    } catch (ClassNotFoundException e) {
      // Create a dummy class with name starting with kotlinx.
      kotlinxClass = new Object() {
        @Override
        public String toString() {
          return "kotlinx.coroutines.CoroutineScope";
        }
      }.getClass();
    }
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(kotlinxClass));
  }

  @Test
  void testIsAnyPlatformType_withScalaPackage() throws Exception {
    Class<?> scalaClass;
    try {
      scalaClass = Class.forName("scala.collection.Seq");
    } catch (ClassNotFoundException e) {
      scalaClass = new Object() {
        @Override
        public String toString() {
          return "scala.collection.Seq";
        }
      }.getClass();
    }
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(scalaClass));
  }

  @Test
  void testIsAnyPlatformType_withNonPlatformType() {
    Class<?> nonPlatformClass = ReflectionAccessFilterHelperTest.class;
    assertFalse(ReflectionAccessFilterHelper.isAnyPlatformType(nonPlatformClass));
  }

  // Dummy class to simulate kotlin package class
  static class KotlinDummy {
    @Override
    public String toString() {
      return "kotlin.Dummy";
    }
  }
}
